| data10 = {{#switch:{{{admin_center|}}}
  |capital | =
  |[[{{{capital|}}}]] =
  |{{{capital|}}} =
  |#default = {{{admin_center}}}{{#if:{{{capital|}}}||{{#if:{{{coordinates|}}}|<br/>{{#invoke:Coordinates|coordinsert|{{{coordinates}}}|type:city}}}} }} }}

| rowclass11 = {{#if:{{{capital|}}}{{{admin_center|}}}|mergedbottomrow}}
