                           | {{{largest_city|}}}{{{largest_settlement|}}} = capital
                           | not capital
                          }}<!--
                    -->}}|capital <!--
    (#ifeq:)-->|<!-- nothing already appears above -->
               | {{if empty| {{{largest_city|}}} | {{{largest_settlement|}}} }}
               }}

