                      -->}}<!--
                   -->}}<!--
                -->}}<!--
               -->| {{error|Error: Invalid HDI value}}{{#ifeq: {{NAMESPACE}} | {{ns:0}} | [[Category:Country articles requiring maintenance]] }}<!--
              -->}}<!--
           -->}}<!--
